import java.util.*; public class Solution { public static long run(List<String> rows) { long hash = 1469598103934665603L; for (String row : rows) { int u = Integer.parseInt(row.substring(2, 4)); int s = Integer.parseInt(row.substring(6, 8)); int f = Integer.parseInt(row.substring(11, 12)); long v = (u & 2047) + s + f * 19L; hash ^= (v + 1); hash *= 1099511628211L; } return hash; } }